var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장님, 괴로운 심경은 이해하지만 이제 통신은 중단하십시오.","JPN":"機関長、苦しいお心はわかりますが、もう通信は中断してください。","ENG":"Chief, I understand your distress, but you must end all comms.","TWN":"機關長，我能理解你難過的心情，不過現在請停止通訊吧。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"시설이 점거된 상태에선 학회 측이 저희들의 위치까지 추적할 수 있습니다.","JPN":"施設が占拠された状態では、学会に我々の位置まで追跡されかねません。","ENG":"With the facility in their hands, the Society will be able to track our location.","TWN":"設施被佔領的狀態下，學會方面能夠追蹤到我們的位置。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리의 경고대로네요. 일이 원하는 대로 풀리지 않아요.","JPN":"古い声の警告どおりですわね。望むようにことが進みません。","ENG":"It is just like the Old Voice warned. Nothing is going as planned.","TWN":"果然就像老聲音警告的那樣，事情不會按照我希望的那樣順利解決。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"합중국의 대통령인지. 혹은 봉인 시설인지.","JPN":"合衆国の大統領か。それとも隔離施設か。","ENG":"Choosing either the president of the States or the quarantine facility...","TWN":"是合眾國的總統，還是隔離設施。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"어느 쪽을 택할지는 정치적이기 이전에 클리포트 게임과도 관계가 있었을 겁니다.","JPN":"どちらを選ぶかは政治的である以前に、クリフォトゲームとも関係があったはずです。","ENG":"Whichever you choose will have some influence in politics and Qliphoth Game.","TWN":"究竟選擇哪一個，既是政治角力，同時也和逆卡巴拉遊戲有關。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장님도 머리로는 이해하고 계시겠죠.","JPN":"機関長も頭では理解されていたことでしょう。","ENG":"I'm sure you understand the risks involved.","TWN":"機關長應該也很清楚吧。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리에게 학회장……","JPN":"古い声から学会長……","ENG":"Since you received word from Old Voice...","TWN":"從由老聲音那裡收到學會長……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아니. 탐식자가 최초의 인형이란 개체와 접촉했다는 정보를 수령했을 때부터.","JPN":"いえ。貪食者が最初の人形という個体と接触したという情報を入手した時から。","ENG":"That the Society president, I mean, the Devourer, had made contact with the Original Puppet.","TWN":"不，我是說，貪食者和最初的人偶這個個體接觸過的情報開始。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"저희 힘만으로는 대응하기 어려운 상황이 되었단 사실을 말입니다.","JPN":"我々の力だけでは対応しきれない状況になったという事実を。","ENG":"We cannot respond to this challenging situation on our own, that much is true.","TWN":"僅憑我們的力量就很難應對了，這個事實。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"최우선 과제는 <color=#ffd34c>게임</color>을 선언한 마왕…….","JPN":"最優先の課題は<color=#ffd34c>ゲーム</color>を宣言した魔王……","ENG":"But our top priority is the Demon Lord who declared <color=#ffd34c>the game</color>...","TWN":"當務之急是宣告<color=#ffd34c>遊戲</color>的魔王……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그 말대로라면, 여기서 엔터프라이즈의 발이 묶였다간 전황에도 악영향이 갈 겁니다.","JPN":"その言葉どおりなら、ここでエンタープライズが足止めを食らうと、戦況にも悪影響を及ぼすはずです。","ENG":"If that is true, then if the Enterprise gets stranded here, it will negatively affect the outcome of the battle.","TWN":"如果照她所說，企業一旦被拖在這裡，也會對戰局產生負面影響。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 모건에 대해서는 너무 걱정하지 마십시오.","JPN":"ですので、モーガンのことはあまりご心配なさらないでください。","ENG":"So don't worry too much about Morgan.","TWN":"所以，你別太擔心摩根了。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"결국 저희가 하려는 건… 치기 어린 말일 수도 있지만 세상을 위해서입니다.","JPN":"結局我々がしようとしていることは……幼稚な言い方かもしれませんが、世界のためです。","ENG":"Ultimately, what we are trying to achieve here is... though it may sound naive, is for the betterment of the world.","TWN":"這話聽起來可能有些幼稚，但最終我們要做的……都是為了這個世界。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"마에스트로를 빌미로 모이게 한 이들 모두……","JPN":"マエストロを口実に呼び集めた者たちはみんな……","ENG":"All the people we summoned here to stop Maestra...","TWN":"以指揮家為藉口聚集起來的這些人……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저희의 결단에 따라선 분명 유용한 전력이 되어 주겠죠?","JPN":"私たちの決断によっては、きっと有効な戦力になってくれるでしょうね。","ENG":"They'll serve us well depending on our decision, right?","TWN":"根據我們的決斷，肯定都會成為有用的戰鬥力吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"만약 다른 생각이 있으시다면, 저도 이번만큼은 이견을 내진 않겠습니다.","JPN":"もし他にお考えがあるのでしたら、私も今度だけは異論を唱えることはしません。","ENG":"If you have other ideas, I will not disagree with you this time.","TWN":"如果你有其他想法。那這次我也不會提出異議。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……그래요. 가끔은 맥크레디 양처럼 악녀라고 손가락질 받는 것도 나쁘지 않겠네요.","JPN":"……そう。たまにはマクレディーさんのように悪女と後ろ指さされるのも悪くありませんわ。","ENG":"...Very well. I suppose it's not all bad to be branded as the villain like Ms. MacCready every now and then.","TWN":"……好的。偶爾像麥克蕾蒂那樣，被人稱為魔女也沒什麼不好的。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물벼룩에게 연락하세요. 훈련실에서 혼나기 싫으면 지금 당장 합류하라고.","JPN":"ミジンコに連絡してください。訓練室で怒られたくなければ、今すぐ合流しなさいと。","ENG":"Contact Water Flea and tell him to come immediately if he doesn't want to get scolded in the training room.","TWN":"請聯絡水蚤。不想在訓練室挨罵，就現在馬上會合。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금은 당면한 문제에 집중하겠습니다.","JPN":"今は当面の問題に集中しましょう。","ENG":"For now, let's focus on the problem at hand.","TWN":"現在我會集中精力解決眼前的問題。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};